const SelectPicker={options:[],selectedValue:null,onSelect:null,title:"",multiSelect:!1,selectedValues:[],init(){this.createPicker()},createPicker(){document.getElementById("selectPickerModal")||(document.body.insertAdjacentHTML("beforeend",'\n            <div class="select-picker-modal" id="selectPickerModal">\n                <div class="select-picker-content">\n                    <div class="select-picker-header">\n                        <button class="select-picker-cancel" id="selectPickerCancel">取消</button>\n                        <h3 id="selectPickerTitle">选择</h3>\n                        <button class="select-picker-confirm" id="selectPickerConfirm">确定</button>\n                    </div>\n                    <div class="select-picker-list" id="selectPickerList"></div>\n                </div>\n            </div>\n        '),this.bindEvents())},bindEvents(){document.getElementById("selectPickerCancel").addEventListener("click",(()=>this.hide())),document.getElementById("selectPickerConfirm").addEventListener("click",(()=>this.confirm()))},show(e,t,s,i="选择",c=!1){this.options=e,this.selectedValue=t,this.onSelect=s,this.title=i,this.multiSelect=c,this.selectedValues=c&&Array.isArray(t)?t:[],document.getElementById("selectPickerTitle").textContent=i,this.renderList(),document.getElementById("selectPickerModal").classList.add("show")},renderList(){const e=document.getElementById("selectPickerList");e.innerHTML=this.options.map((e=>{const t=this.multiSelect?this.selectedValues.includes(e.value):this.selectedValue===e.value;return`\n                <div class="select-picker-item ${t?"selected":""}" data-value="${e.value}">\n                    <span class="select-picker-label">${e.label}</span>\n                    ${t?'<span class="select-picker-check">✓</span>':""}\n                </div>\n            `})).join(""),e.querySelectorAll(".select-picker-item").forEach((e=>{e.addEventListener("click",(()=>{const t=e.dataset.value;if(this.multiSelect){const e=this.selectedValues.indexOf(t);e>-1?this.selectedValues.splice(e,1):this.selectedValues.push(t),this.renderList()}else this.selectedValue=t,this.renderList(),setTimeout((()=>this.confirm()),200)}))}))},hide(){document.getElementById("selectPickerModal").classList.remove("show")},confirm(){this.onSelect&&(this.multiSelect?this.onSelect(this.selectedValues):this.onSelect(this.selectedValue)),this.hide()}};